"use strict";(self.webpackChunkastrology_garden=self.webpackChunkastrology_garden||[]).push([["800"],{9780(e,n,i){i.r(n),i.d(n,{metadata:()=>o,default:()=>u,frontMatter:()=>s,contentTitle:()=>r,toc:()=>l,assets:()=>c});var o=JSON.parse('{"id":"Stellar bodies/sun","title":"sun","description":"Principle:","source":"@site/docs/Stellar bodies/sun.md","sourceDirName":"Stellar bodies","slug":"/Stellar bodies/sun","permalink":"/docs/Stellar bodies/sun","draft":false,"unlisted":false,"editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/docs/Stellar bodies/sun.md","tags":[],"version":"current","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"saturn","permalink":"/docs/Stellar bodies/saturn"},"next":{"title":"uranus","permalink":"/docs/Stellar bodies/uranus"}}'),a=i(4848),t=i(8453);let s={},r,c={},l=[{value:"T\u0142umaczenie na j\u0119zyk polski (Translation)",id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",level:3}];function d(e){let n={h3:"h3",li:"li",p:"p",ul:"ul",...(0,t.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n.p,{children:"Principle:"}),"\n",(0,a.jsx)(n.p,{children:"Spirit, mind, the living being."}),"\n",(0,a.jsx)(n.p,{children:"Psychological Correspondence:"}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsx)(n.li,{children:"The will to live, the urge to rule, the striving for an objective, organisation, the ability to make a decision."}),"\n",(0,a.jsx)(n.li,{children:"Lack of vitality and will-power, lack of determination and organisation, indecision or vacillation."}),"\n"]}),"\n",(0,a.jsx)(n.p,{children:"Biological Correspondence:"}),"\n",(0,a.jsx)(n.p,{children:"Health, vitality, the heart, the circulation. \u2013 The body, the cell."}),"\n",(0,a.jsx)(n.p,{children:"Sociological Correspondence:"}),"\n",(0,a.jsx)(n.p,{children:"Man, father, authority, leading personality, official or civil servant."}),"\n",(0,a.jsx)(n.p,{children:"Position in Houses and Signs:"}),"\n",(0,a.jsx)(n.p,{children:"I. Storming and urging nature, leading nature or character, the urge to do something, consciousness of purpose or objective, enthusiasm, courage, boldness and audacity, passion, the urge to rule or lust for power, quarrelsomeness. \u2013 Advancement in life partly through ruthlessness. Difficulties through hastiness."}),"\n",(0,a.jsx)(n.p,{children:"II. Rich soul-life, perseverance, endurance, constructiveness, sense of form, humor, material outlook, practical nature, love of pleasure and enjoyment. \u2013 Money-matters are often important. Striving for secure circumstances in life."}),"\n",(0,a.jsx)(n.p,{children:"III. Vivaciousness, joy of life, versatility, adaptability, restlessness, superficiality, eagerness to learn or study, the faculty to absorb or grasp a subject, love of change, fluctuating inclinations."}),"\n",(0,a.jsx)(n.p,{children:"IV. Wealth of feeling, joy of marriage, connubial love, receptivity, impressionability, benevolence, contemplative nature, reserve, domesticity, love of comfort; harmonious family-life. The experience of ups and downs in life."}),"\n",(0,a.jsx)(n.p,{children:"V. Domineering people, self-confidence, formative energy, creativity, self-assuredness, the striving for possessions, wealth of ideas, organisation, the quality of leadership, rise and advancement in life through one's own personal ability, patronage and protection."}),"\n",(0,a.jsx)(n.p,{children:"VI. Care and diligence or attention, orderliness, correctness, sense of criticism, a methodical mind, analytical ability, simplicity, contentment. \u2013 Enmity caused through fault-finding. Extensive studies; good opportunities are often missed."}),"\n",(0,a.jsx)(n.p,{children:"VII. Harmony, public spirit, sociableness, adaptation, vanity, the desire to be a person of importance, love of the arts, good manners. Lack of firmness, consistency, constancy. Associations are important."}),"\n",(0,a.jsx)(n.p,{children:"VIII. People with will-power. \u2013 The struggle for existence, the power to succeed and to maintain one's position in life, tenacity, overestimation of self, excessive passion, fearlessness, fanaticism. Quarrels, difficulties caused through one's own fault or attitude."}),"\n",(0,a.jsx)(n.p,{children:"IX. Mobility, readiness for action, love of sport, generosity, idealism, enthusiasm. \u2013 Sociableness, changeable mood, dual nature. \u2013 Striving for a secure position in life, slow advancement, important associations."}),"\n",(0,a.jsx)(n.p,{children:"X. Hard-working people. \u2013 Concentration upon the self, a serious outlook on life, tenacious clinging to one's goal or aspiration in life, tenacity or toughness, industriousness, a sense of reality. Rise and advancement through untiring effort, vocational interests are of primary importance."}),"\n",(0,a.jsx)(n.p,{children:"XI. Good powers of observation, intuitive understanding of other people, adaptability, mutability, readiness to help others, sociability, knowledge of human nature, a sympathetic attitude towards new ways or methods. \u2013 Rebellion against tutelage or restriction. Rise and advancement through one's effort, but also through help coming from others."}),"\n",(0,a.jsx)(n.p,{children:"XII. Reserve, receptiveness, the faculty to absorb, moodiness, patience, negligence, love of comfort, a secretive nature. Restrictions in life caused through inner inhibitions, difficulties caused through a negative attitude."}),"\n",(0,a.jsx)(n.h3,{id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",children:"T\u0142umaczenie na j\u0119zyk polski (Translation)"}),"\n",(0,a.jsx)(n.p,{children:"Zasada:"}),"\n",(0,a.jsx)(n.p,{children:"Duch, umys\u0142, istota \u017Cywa."}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja psychologiczna:"}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsx)(n.li,{children:"Wola \u017Cycia, pragnienie rz\u0105dzenia, d\u0105\u017Cenie do celu, organizacja, zdolno\u015B\u0107 podejmowania decyzji."}),"\n",(0,a.jsx)(n.li,{children:"Brak witalno\u015Bci i si\u0142y woli, brak determinacji i organizacji, niezdecydowanie lub chwiejno\u015B\u0107."}),"\n"]}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja biologiczna:"}),"\n",(0,a.jsx)(n.p,{children:"Zdrowie, witalno\u015B\u0107, serce, kr\u0105\u017Cenie. \u2013 Cia\u0142o, kom\xf3rka."}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja socjologiczna:"}),"\n",(0,a.jsx)(n.p,{children:"M\u0119\u017Cczyzna, ojciec, autorytet, wiod\u0105ca osobowo\u015B\u0107, urz\u0119dnik lub funkcjonariusz publiczny."}),"\n",(0,a.jsx)(n.p,{children:"Pozycja w domach i znakach:"}),"\n",(0,a.jsx)(n.p,{children:"I. Burzliwa i nagl\u0105ca natura, wiod\u0105ca natura lub charakter, pragnienie dzia\u0142ania, \u015Bwiadomo\u015B\u0107 celu lub d\u0105\u017Cenia, entuzjazm, odwaga, \u015Bmia\u0142o\u015B\u0107 i zuchwa\u0142o\u015B\u0107, nami\u0119tno\u015B\u0107, pragnienie rz\u0105dzenia lub \u017C\u0105dza w\u0142adzy, k\u0142\xf3tliwo\u015B\u0107. \u2013 Awans w \u017Cyciu cz\u0119\u015Bciowo przez bezwzgl\u0119dno\u015B\u0107. Trudno\u015Bci z powodu po\u015Bpiechu."}),"\n",(0,a.jsx)(n.p,{children:"II. Bogate \u017Cycie wewn\u0119trzne (duszy), wytrwa\u0142o\u015B\u0107, wytrzyma\u0142o\u015B\u0107, konstruktywno\u015B\u0107, zmys\u0142 formy, humor, materialne spojrzenie, praktyczna natura, zami\u0142owanie do przyjemno\u015Bci i uciech. \u2013 Sprawy finansowe s\u0105 cz\u0119sto wa\u017Cne. D\u0105\u017Cenie do bezpiecznych warunk\xf3w \u017Cyciowych."}),"\n",(0,a.jsx)(n.p,{children:"III. \u017Bywio\u0142owo\u015B\u0107, rado\u015B\u0107 \u017Cycia, wszechstronno\u015B\u0107, zdolno\u015B\u0107 adaptacji, niepok\xf3j, powierzchowno\u015B\u0107, ch\u0119\u0107 do nauki lub studiowania, zdolno\u015B\u0107 do przyswajania lub pojmowania zagadnienia, mi\u0142o\u015B\u0107 do zmian, zmienne sk\u0142onno\u015Bci."}),"\n",(0,a.jsx)(n.p,{children:"IV. Bogactwo uczu\u0107, rado\u015B\u0107 z ma\u0142\u017Ce\u0144stwa, mi\u0142o\u015B\u0107 ma\u0142\u017Ce\u0144ska, receptywno\u015B\u0107, podatno\u015B\u0107 na wra\u017Cenia, \u017Cyczliwo\u015B\u0107, kontemplacyjna natura, rezerwa, przywi\u0105zanie do ogniska domowego, zami\u0142owanie do wygody; harmonijne \u017Cycie rodzinne. Do\u015Bwiadczanie wzlot\xf3w i upadk\xf3w w \u017Cyciu."}),"\n",(0,a.jsx)(n.p,{children:"V. Dominuj\u0105cy ludzie, pewno\u015B\u0107 siebie, energia tw\xf3rcza, kreatywno\u015B\u0107, samoupewnienie, d\u0105\u017Cenie do posiadania, bogactwo pomys\u0142\xf3w, organizacja, cechy przyw\xf3dcze, wzrost i awans w \u017Cyciu dzi\u0119ki w\u0142asnym osobistym zdolno\u015Bciom, mecenat i ochrona."}),"\n",(0,a.jsx)(n.p,{children:"VI. Troska i pilno\u015B\u0107 lub uwaga, uporz\u0105dkowanie, poprawno\u015B\u0107, zmys\u0142 krytycyzmu, metodyczny umys\u0142, zdolno\u015B\u0107 analityczna, prostota, zadowolenie. \u2013 Wrogo\u015B\u0107 wywo\u0142ana szukaniem dziury w ca\u0142ym (wytykaniem b\u0142\u0119d\xf3w). Obszerne studia; dobre okazje s\u0105 cz\u0119sto marnowane."}),"\n",(0,a.jsx)(n.p,{children:"VII. Harmonia, zmys\u0142 spo\u0142eczny, towarzysko\u015B\u0107, adaptacja, pr\xf3\u017Cno\u015B\u0107, pragnienie bycia wa\u017Cn\u0105 osob\u0105, mi\u0142o\u015B\u0107 do sztuki, dobre maniery. Brak stanowczo\u015Bci, konsekwencji, sta\u0142o\u015Bci. Zwi\u0105zki (partnerstwa) s\u0105 wa\u017Cne."}),"\n",(0,a.jsx)(n.p,{children:"VIII. Ludzie z si\u0142\u0105 woli. \u2013 Walka o byt, si\u0142a by odnie\u015B\u0107 sukces i utrzyma\u0107 swoj\u0105 pozycj\u0119 w \u017Cyciu, nieust\u0119pliwo\u015B\u0107, przecenianie samego siebie, nadmierna nami\u0119tno\u015B\u0107, nieustraszono\u015B\u0107, fanatyzm. K\u0142\xf3tnie, trudno\u015Bci spowodowane w\u0142asn\u0105 win\u0105 lub postaw\u0105."}),"\n",(0,a.jsx)(n.p,{children:"IX. Mobilno\u015B\u0107, gotowo\u015B\u0107 do dzia\u0142ania, mi\u0142o\u015B\u0107 do sportu, wielkoduszno\u015B\u0107, idealizm, entuzjazm. \u2013 Towarzysko\u015B\u0107, zmienny nastr\xf3j, dualistyczna natura. \u2013 D\u0105\u017Cenie do bezpiecznej pozycji w \u017Cyciu, powolny awans, wa\u017Cne zwi\u0105zki."}),"\n",(0,a.jsx)(n.p,{children:"X. Ludzie ci\u0119\u017Cko pracuj\u0105cy. \u2013 Koncentracja na sobie, powa\u017Cne spojrzenie na \u017Cycie, wytrwa\u0142e trzymanie si\u0119 swojego celu lub d\u0105\u017Cenia w \u017Cyciu, nieust\u0119pliwo\u015B\u0107 lub twardo\u015B\u0107, pracowito\u015B\u0107, poczucie rzeczywisto\u015Bci. Wzrost i awans dzi\u0119ki niestrudzonemu wysi\u0142kowi, zainteresowania zawodowe maj\u0105 pierwszorz\u0119dne znaczenie."}),"\n",(0,a.jsx)(n.p,{children:"XI. Dobra zdolno\u015B\u0107 obserwacji, intuicyjne rozumienie innych ludzi, zdolno\u015B\u0107 adaptacji, zmienno\u015B\u0107, gotowo\u015B\u0107 do pomagania innym, towarzysko\u015B\u0107, znajomo\u015B\u0107 natury ludzkiej, \u017Cyczliwa postawa wobec nowych sposob\xf3w lub metod. \u2013 Bunt przeciwko kurateli lub ograniczeniom. Wzrost i awans dzi\u0119ki w\u0142asnemu wysi\u0142kowi, ale tak\u017Ce dzi\u0119ki pomocy p\u0142yn\u0105cej od innych."}),"\n",(0,a.jsx)(n.p,{children:"XII. Rezerwa, receptywno\u015B\u0107, zdolno\u015B\u0107 przyswajania, humorzasto\u015B\u0107, cierpliwo\u015B\u0107, zaniedbanie, zami\u0142owanie do wygody, skryta natura. Ograniczenia w \u017Cyciu spowodowane wewn\u0119trznymi zahamowaniami, trudno\u015Bci spowodowane negatywn\u0105 postaw\u0105."})]})}function u(e={}){let{wrapper:n}={...(0,t.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},8453(e,n,i){i.d(n,{R:()=>s,x:()=>r});var o=i(6540);let a={},t=o.createContext(a);function s(e){let n=o.useContext(t);return o.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),o.createElement(t.Provider,{value:n},e.children)}}}]);